import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface Animal {
  id: number;
  identificador_unico: string;
  nombre: string;
  sexo: string;
  categoria: string;
  estado: string;
  raza_nombre: string;
  ubicacion_nombre: string;
  fecha_nacimiento: string;
}

const Animals: React.FC = () => {
  const [animals, setAnimals] = useState<Animal[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    identificador_unico: '',
    nombre: '',
    sexo: 'hembra',
    categoria: 'lechon',
    fecha_nacimiento: ''
  });

  useEffect(() => {
    loadAnimals();
  }, []);

  const loadAnimals = async () => {
    try {
      const response = await api.get('/animals');
      setAnimals(response.data);
    } catch (error) {
      console.error('Error cargando animales:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('/animals', formData);
      setShowForm(false);
      setFormData({
        identificador_unico: '',
        nombre: '',
        sexo: 'hembra',
        categoria: 'lechon',
        fecha_nacimiento: ''
      });
      loadAnimals();
    } catch (error) {
      console.error('Error creando animal:', error);
    }
  };

  if (loading) return <div className="loading">Cargando animales...</div>;

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-3">
        <h1>Gestión de Animales</h1>
        <button 
          className="btn btn-primary"
          onClick={() => setShowForm(!showForm)}
        >
          {showForm ? 'Cancelar' : 'Nuevo Animal'}
        </button>
      </div>

      {showForm && (
        <div className="card mb-3">
          <h3>Registrar Nuevo Animal</h3>
          <form onSubmit={handleSubmit}>
            <div className="grid grid-2">
              <div className="form-group">
                <label>Identificador Único:</label>
                <input
                  type="text"
                  className="form-control"
                  value={formData.identificador_unico}
                  onChange={(e) => setFormData({...formData, identificador_unico: e.target.value})}
                  required
                />
              </div>
              <div className="form-group">
                <label>Nombre:</label>
                <input
                  type="text"
                  className="form-control"
                  value={formData.nombre}
                  onChange={(e) => setFormData({...formData, nombre: e.target.value})}
                />
              </div>
              <div className="form-group">
                <label>Sexo:</label>
                <select
                  className="form-control"
                  value={formData.sexo}
                  onChange={(e) => setFormData({...formData, sexo: e.target.value})}
                >
                  <option value="hembra">Hembra</option>
                  <option value="macho">Macho</option>
                </select>
              </div>
              <div className="form-group">
                <label>Categoría:</label>
                <select
                  className="form-control"
                  value={formData.categoria}
                  onChange={(e) => setFormData({...formData, categoria: e.target.value})}
                >
                  <option value="lechon">Lechón</option>
                  <option value="recria">Recría</option>
                  <option value="desarrollo">Desarrollo</option>
                  <option value="engorde">Engorde</option>
                  <option value="reproductor">Reproductor</option>
                </select>
              </div>
              <div className="form-group">
                <label>Fecha de Nacimiento:</label>
                <input
                  type="date"
                  className="form-control"
                  value={formData.fecha_nacimiento}
                  onChange={(e) => setFormData({...formData, fecha_nacimiento: e.target.value})}
                />
              </div>
            </div>
            <button type="submit" className="btn btn-success">Guardar Animal</button>
          </form>
        </div>
      )}

      <div className="card">
        <h3>Lista de Animales ({animals.length})</h3>
        {animals.length > 0 ? (
          <table className="table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Nombre</th>
                <th>Sexo</th>
                <th>Categoría</th>
                <th>Estado</th>
                <th>Raza</th>
                <th>Ubicación</th>
                <th>Nacimiento</th>
              </tr>
            </thead>
            <tbody>
              {animals.map(animal => (
                <tr key={animal.id}>
                  <td>{animal.identificador_unico}</td>
                  <td>{animal.nombre || '-'}</td>
                  <td style={{textTransform: 'capitalize'}}>{animal.sexo}</td>
                  <td style={{textTransform: 'capitalize'}}>{animal.categoria}</td>
                  <td>
                    <span style={{
                      padding: '4px 8px',
                      borderRadius: '4px',
                      fontSize: '12px',
                      backgroundColor: animal.estado === 'activo' ? '#d4edda' : '#f8d7da',
                      color: animal.estado === 'activo' ? '#155724' : '#721c24'
                    }}>
                      {animal.estado}
                    </span>
                  </td>
                  <td>{animal.raza_nombre || '-'}</td>
                  <td>{animal.ubicacion_nombre || '-'}</td>
                  <td>{animal.fecha_nacimiento ? new Date(animal.fecha_nacimiento).toLocaleDateString() : '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p className="text-center" style={{padding: '40px', color: '#7f8c8d'}}>
            No hay animales registrados
          </p>
        )}
      </div>
    </div>
  );
};

export default Animals;
